window.__QUIZ_DATA__=[{"id":"theory>Physics>2001>PART I>1>i","subject":"Physics","year":"2001","type":"Theory","sub_label":"i","group":"FINAL","topic":"MOTION : MOTION UNDER GRAVITY","question":"A ball thrown vertically upward reaches a maximum height of 50m  above the level of projection.calculate the    time taken to reach the maximum height","images":[],"marking_scheme":"To reach maximum height, V = 0  where a = -g,  t = time  u = initial velocity  Using second equation of motion,  S=12gt2  S = 50m, g = 10ms-2  substituting,  50=12(10)t2  t2=505  t2 = 10  t = &radic;10&nbsp; = 3.3 seconds","marks":"2","difficulty":"2"},{"id":"theory>Physics>2001>PART I>1>ii","subject":"Physics","year":"2001","type":"Theory","sub_label":"ii","group":"FINAL","topic":"MOTION : MOTION UNDER GRAVITY","question":"A ball thrown vertically upward reaches a maximum height of 50m  above the level of projection.calculate the   Speed of the throw.[g = 10ms-2]","images":[],"marking_scheme":"Using third equation of motion  V2 = U2 + 2as  (U = 0)  Therefore, V2 = 2as  V2 = 2 \u00d7 10 \u00d7 50  V2 = 1000  V = 31.62ms-1","marks":"1","difficulty":"2"},{"id":"theory>Physics>2001>PART I>2","subject":"Physics","year":"2001","type":"Theory","sub_label":"2","group":"","topic":"PROJECTILE MOTION :","question":"A lead shot is projected from the ground level with a velocity u at an angle \u03b8 to horizontal. Given The time , t for the lead shot to reach its maximum height as t = usin\u03b8/g. where ''g'' is the acceleration of free fall due to gravity, show that the greatest height reached by body is hmax = u2sin2\u03b8/2g","images":[],"marking_scheme":"At maximum height, velocity is zero  Using second equation of motion,  S=Ut+12gt2  Since U = 0  S=12gt2  butt=usin\u03b8gfromquestion  substituting for t we have  S=12g(U2sin2\u03b8g)2  S=12g(U2sin2\u03b8g2)  S=U2sin2\u03b82g  therefore,  H=U2sin2\u03b82g","marks":"3","difficulty":"3"},{"id":"theory>Physics>2001>PART I>3>a","subject":"Physics","year":"2001","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELECTRIC FIELD : ELECTROSTATICS","question":"what is electrolysis?","images":[],"marking_scheme":"Electrolysis is the passing of a direct electric current through an ionic substance that is either molten or dissolved in a suitable solvent, producing chemical reactions at the electrodes and decomposition of the materials.","marks":"2","difficulty":"1"},{"id":"theory>Physics>2001>PART I>3>b","subject":"Physics","year":"2001","type":"Theory","sub_label":"b","group":"FINAL","topic":"ELECTRIC FIELD : CURRENT ELECTRICITY","question":"A current of 2A is passed through a copper voltameter for 5minutes. if the electrochemical equivalent of copper is 3.27\u00d710-7kgC-1 determine the mass of copper deposited.","images":[],"marking_scheme":"Current = 2A  Time = 5 minutes = 5 \u00d7 60 = 300 seconds  Mass of copper deposited = ZIt  M = (3.27 x 10-7 x 2 x 5 x 60)kg = 0.0001962kg","marks":"1","difficulty":"2"},{"id":"theory>Physics>2001>PART I>4","subject":"Physics","year":"2001","type":"Theory","sub_label":"4","group":"CLOSENESS","topic":"ELECTRIC FIELD : ELECTROSTATICS","question":"The value of e.m.f of a voltaic cell which has dilute tetraoxosulphate(VI)acid as its electrolyte and copper and zinc as its electrodes becomes less with use. Explain this observation and state show how it can be corrected.","images":[],"marking_scheme":"Zinc reacts with H2SO4 to produce hydrogen bubbles. These bubbles are deposited on the copper plate, the copper electrodes become insulated. Therefore, the emf drops.    Corrected   - Using depolarizer  - Brushing of plates","marks":"3","difficulty":"3"},{"id":"theory>Physics>2001>PART I>5>a","subject":"Physics","year":"2001","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"LIGHT WAVES : SOURCES OF LIGHT","question":"What is meant by a beam of polarised light","images":[],"marking_scheme":"Polarized light is the collection of rays which have been restricted to move in one direction.","marks":"1","difficulty":"2"},{"id":"theory>Physics>2001>PART I>5>b","subject":"Physics","year":"2001","type":"Theory","sub_label":"b","group":"","topic":"LIGHT WAVES : SOURCES OF LIGHT","question":"with the aid of a well labelled diagram, illustrate the action of a polaroid spectacle on a beam of sunlight","images":["data:image/png;base64,"],"marking_scheme":"The polarizer transmits only plane polarized light.","marks":"2","difficulty":"2"},{"id":"theory>Physics>2001>PART I>6>a","subject":"Physics","year":"2001","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELECTRIC FIELD : ELECTRIC CONDUCTION THROUGH MATERIALS","question":"Explain how a gas can be made to conduct electricity","images":[],"marking_scheme":"Gas placed in a discharge tube under very low pressure conducts electricity, at the end of the tube we have electrodes.  High voltage is applied at the electrodes, at low pressure and high temperature.  The glowing is as a result of charged electrons.","marks":"1","difficulty":"2"},{"id":"theory>Physics>2001>PART I>6>b","subject":"Physics","year":"2001","type":"Theory","sub_label":"b","group":"","topic":"ELECTRIC FIELD : ELECTRIC CONDUCTION THROUGH MATERIALS","question":"Name the electric charge carrier in gases","images":["data:image/png;base64,"],"marking_scheme":"","marks":"2","difficulty":"1"},{"id":"theory>Physics>2001>PART I>7>a","subject":"Physics","year":"2001","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"State two properties of cathode rays","images":[],"marking_scheme":"1. Cathode rays are negatively charged.  2. Cathode rays cause some materials to glow.","marks":"2","difficulty":"1"},{"id":"theory>Physics>2001>PART I>7>b","subject":"Physics","year":"2001","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"Explain how the intensity and energy of cathode rays may be increased","images":[],"marking_scheme":"Increase in potential difference between the anode and cathode, current will be increased as a result. The intensity of the cathode rays vary directly with current.  Increase in temperature and lowering of pressure also increases the energy and intensity.","marks":"1","difficulty":"2"},{"id":"theory>Physics>2001>PART I>8","subject":"Physics","year":"2001","type":"Theory","sub_label":"8","group":"","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"The mass and wavelength of a moving electron are 9.0 \u00d710-31kg and 1.0\u00d710-10m respectively. calculate the kinetic energy of the electron. [h = 6.6 \u00d7 10-34 Js]","images":[],"marking_scheme":"mass (m) = 9.0 \u00d7 10-31kg  wavelength (\u22cb) = 1.0 \u00d7 10-10m  V=hm\u22cb  substituting, m and \u22cb  6.6 x 10-349.0 x 10-31 x 1.0 x 10-10  V = 7.3 x 106 ms-1  Kineticenergy=12mV2  =12xmV2  =12x9.0x10-31x(7.3x106)2  \u21d2 2.3982 \u00d7 1014 \u00d7 10-31J  \u21d2 2.4 \u00d7 10-17J","marks":"3","difficulty":"3"},{"id":"theory>Physics>2001>PART I>9>i","subject":"Physics","year":"2001","type":"Theory","sub_label":"i","group":"FINAL","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"The diagram above represent the graph of electron energy against the frequency of the radiation incident on a metal surface. interpret the       Slope of the graph","images":["data:image/png;base64,"],"marking_scheme":"Slope=eVF  where eV = energy in Joules  F = Frequency in hertz  eV = hF (h = plank contant)  Therefore, S=hFF  S = h","marks":"1","difficulty":"2"},{"id":"theory>Physics>2001>PART I>9>ii","subject":"Physics","year":"2001","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"The diagram above represent the graph of electron energy against the frequency of the radiation incident on a metal surface. interpret the     inercept, OC;","images":["data:image/png;base64,"],"marking_scheme":"The intercept is the minimum energy required to liberate an electron from a metal surface. It is known as the work function.","marks":"1","difficulty":"2"},{"id":"theory>Physics>2001>PART I>9>iii","subject":"Physics","year":"2001","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"The diagram above represent the graph of electron energy against the frequency of the radiation incident on a metal surface. interpret the     intercept, OK","images":["data:image/png;base64,"],"marking_scheme":"(OK) is the threshold frequency  This is the minimum frequency of radiation that will produce photoelectric effect.","marks":"1","difficulty":"3"},{"id":"theory>Physics>2001>PART I>10>a","subject":"Physics","year":"2001","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"HOOKE\u2019S LAW, YOUNG\u2019S MODULES AND WORK DONE IN SPRINGS AND STRING :","question":"Distinguish between stress and strain as used in used elasticity.","images":[],"marking_scheme":"Stress is the force acting on a material per unit area (cross sectional area). (Nm-2) while strain is the ratio of extension to the original length of the material. It has no unit.","marks":"1","difficulty":"2"},{"id":"theory>Physics>2001>PART I>10>b","subject":"Physics","year":"2001","type":"Theory","sub_label":"b","group":"FINAL","topic":"WORK, ENERGY AND POWER : CONCEPT OF WORK","question":"When a force of 40N is applied to be free end of an elastic cord, an extension of 5cm is produced in the cord. calculate the work done on the cord.","images":[],"marking_scheme":"Using hooke's law,  F = Ke   making K the subject of formular   K=Fe=400.05=800Nm-1  Work=12Ke2  substituting values in,  12x800x(0.05)2=1J","marks":"2","difficulty":"2"},{"id":"theory>Physics>2001>PART II>11>a","subject":"Physics","year":"2001","type":"Theory","sub_label":"a","group":"FINAL","topic":"PROJECTILE MOTION :","question":"In first attempt, long jumper took off from the spring board with a speed of 8ms-1 at 30\u2218 to the horizontal. he makes a second attempt with the same speed at 45\u2218 to the horizontal.Given that the expression for the horizontal ange of the projectile is v2sin2\u03b8/g where all the symbols have their usual meanings, show that he gains a distance of 0.8576m in his second attempt","images":[],"marking_scheme":"In His first attempt,  R1=V2sin2\u03b8g  substituting values in   R=82sin6010=64 \u00d7 0.866010=5.5424    In his second attempt  R2=82sin2 \u00d7 4510=64\u00d7110=6.4  Gained distance = R2 - R1 = 6.4 - 5.5424 = 0.8576m","marks":"4","difficulty":"3"},{"id":"theory>Physics>2001>PART II>11>b>i","subject":"Physics","year":"2001","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"HOOKE\u2019S LAW, YOUNG\u2019S MODULES AND WORK DONE IN SPRINGS AND STRING :","question":"State hooke's law of elasticity","images":[],"marking_scheme":"Hooke's law of elasticity states that provided the elastic limit of a material is not exceeded the extension (e), is directly proportional to the force applied.  F \u03b1 e  F = Ke  where, F = Force  e = extension  K = Elasticity constant","marks":"4","difficulty":"1"},{"id":"theory>Physics>2001>PART II>11>b>ii","subject":"Physics","year":"2001","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"HOOKE\u2019S LAW, YOUNG\u2019S MODULES AND WORK DONE IN SPRINGS AND STRING :","question":"Describe an experiment to verify Hook's law","images":["data:image/png;base64,","data:image/png;base64,"],"marking_scheme":"Experiment to verify hooke's law   Materials needed  Spring  Millimeter scale  Pointer  Experiment    Selected loads are placed on the scale pan, this produces an extension on the spring, the extension on loading and off-loading is recorder, the average is used. On each loading, the extension is recorded.  Load (w)Extension on loading (A1(mm) Extension on off loading A2 (mm)Main Extension ( A1+A2/2 )","marks":"4","difficulty":"2"},{"id":"theory>Physics>2001>PART II>11>b>iii","subject":"Physics","year":"2001","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"HOOKE\u2019S LAW, YOUNG\u2019S MODULES AND WORK DONE IN SPRINGS AND STRING :","question":"State two precaution you would take if you were perform this experiment in the laboratory","images":[],"marking_scheme":"- Ensured string was steady before loading   - Avoided zero error in meter rule","marks":"4","difficulty":"1"},{"id":"theory>Physics>2001>PART II>11>c","subject":"Physics","year":"2001","type":"Theory","sub_label":"c","group":"","topic":"HOOKE\u2019S LAW, YOUNG\u2019S MODULES AND WORK DONE IN SPRINGS AND STRING :","question":"A spiral spring of natural lenght 20.00cm has a scale pan hanging freely in its lower end. When an object of mass 40g is placed in the pan , its lenght becomes 21.80cm. when another onject of mass 60g is placed in the pan, the lenght becomes 22.5cm. calculate the mass of the scale pan [g = 10ms-2].","images":[],"marking_scheme":"Natural length L0 = 20.00cm  New length L1 = 21.81cm  Final length L2 = 22.05cm    F1 = 40g = 0.04kg, F2 = 60g = 0.06kg = 0.6N  Mass (F0) = X (unknown)    Using Hooke\\s law,  F \u03b1 e  F = Ke  extension (e1) = L1 - L0 = 1.80cm  extension (e2) = L2 - L0 = 2.05cm    F1 - F0F2 - F0=L1 - L0L2 - L0=0.4 - X0.6 - X  0.4 - X0.6 - X=1.82.05  Cross multiplying,  2.05(0.4 - X) = 1.8(0.6 - X)  \u21d2 1.08 - 1.8X = 0.82 - 2.05X  \u21d2 0.82 - 1.08 = -1.8X + 2.05X  0.26 = 0.25X  X=0.260.25  X = 1.04N; = 0.104Kg    In grams,  X = 0.104kg \u00d7 1000  X = 104 grams","marks":"4","difficulty":"3"},{"id":"theory>Physics>2001>PART II>12>a","subject":"Physics","year":"2001","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"HEAT ENERGY : SPECIFIC HEAT CAPACITY","question":"Define specific heat capacity","images":[],"marking_scheme":"Specific heat capacity of a material is the quantity of heat required to raise the temperature of a unit mass of that material by one degree celcius (1\u00b0C).","marks":"4","difficulty":"1"},{"id":"theory>Physics>2001>PART II>12>b>i","subject":"Physics","year":"2001","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"HEAT ENERGY : SPECIFIC HEAT CAPACITY","question":"Wit the aid of a labelled diagram, describe an experiment to determine the specific heat capacity of copper using a copper ball","images":["data:image/png;base64,"],"marking_scheme":"Materials needed  Thermometers &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp  Heated Copper ball  Stirer  Bunsen Burner  retort stand  Lagged Calorimeter        Procedure  - Arrange apparatus as shown in the diagram.  - Measure and record initial mass (copper ball).  - Half fill the calorimeter with water and measure and record the temperature.  - Burn and stir, and record temperature.  - Perform your mathematical deduction  M1 = Mass of copper ball  M2 = Mass of water  M3 = Mass of calorimeter   \u03b81 = temperature of ball  \u03b82 = temperature of water  \u03b83 = final temperature    Heat lost by the copper ball = Heat gained by water + heat gained by cal  M1Ccal(\u03b81 - \u03b83) = M2Cw(\u03b82 - \u03b83) + M3Ccal(\u03b82 - \u03b83)    Precautions  - Stired mixture thoroughly  - Avoided error due to paralax","marks":"5","difficulty":"2"},{"id":"theory>Physics>2001>PART II>12>b>ii","subject":"Physics","year":"2001","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"HEAT ENERGY : SPECIFIC HEAT CAPACITY","question":"State two precaution necessary to obtain accurate results.","images":[],"marking_scheme":"- The copper ball must be allowed to remain in the steam to attain 100o  - The mixture of copper ball and water must be thoroughly stirred.  - The calorimeter must be properly lagged.","marks":"4","difficulty":"1"},{"id":"theory>Physics>2001>PART II>12>c","subject":"Physics","year":"2001","type":"Theory","sub_label":"c","group":"FINAL","topic":"HEAT ENERGY : SPECIFIC HEAT CAPACITY","question":"A piece of copper block of mass 24g at 230\u2218C is placed in copper calorimeter of mass 60g containing 54g of water at 31\u2218C. Assuming heat losses are neglible, calculate the final steady temperature of the mixture[Specific heat capacity of water = 4200J kg-1k-1, specific heat capacity of copper = 400 Jkg-1k-1]","images":[],"marking_scheme":"From question,  Mass of copper = 24g  Initial temperature of copper = \u03b81 = 230\u00b0C  Mass of calorimeter = 60g  Mass of water = 54g  \u03b82(Initial temperature of water) = 31\u00b0C  Final temperature = ?    Heat lost by copper = Heat gained by water + Heat gained by Calorimeter  McuCcu(\u03b81 - \u03b83) = McalCcal(\u03b83 - \u03b82) + MwCw(\u03b83 - \u03b82)  substituting,  24 x 400 (230 - \u03b83) = 60 x 400 (\u03b83 - 31) + 54 x 4200(\u03b83 - 31)  9600(230 - \u03b83) = 24000(\u03b83 - 31) + 226800(\u03b83 - 31)  9600(230 - \u03b83) = (\u03b83 - 31)[24,000 + 226800]  9600(230 - \u03b83) = 250800(\u03b83 - 31)  expanding and collecting like terms  220800 + 9600 x 230 = 250800\u03b83 + 9600\u03b83  9982800 = 260400\u03b83  \u03b83=9982800260400  \u03b83 = 38.34\u00b0C","marks":"6","difficulty":"3"},{"id":"theory>Physics>2001>PART II>13>a>i","subject":"Physics","year":"2001","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"SOUND WAVES : ECHOES AND REVERBERATION","question":"What is an echo?","images":[],"marking_scheme":"An echo is the sound heard after the reflection of sound from a plane surface.","marks":"2","difficulty":"1"},{"id":"theory>Physics>2001>PART II>13>a>ii","subject":"Physics","year":"2001","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"SOUND WAVES : ECHOES AND REVERBERATION","question":"State two useful application of echoes","images":[],"marking_scheme":"It is applied in gas exploration  It is used in determination of depth  It is used to determine speed of sound","marks":"2","difficulty":"1"},{"id":"theory>Physics>2001>PART II>13>a>iii","subject":"Physics","year":"2001","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"SOUND WAVES : ECHOES AND REVERBERATION","question":"Why are the wall, floor and ceiling of a recording studio heavily padded?","images":[],"marking_scheme":"They are heavily padded to reduce reflection and absorbtion of sound waves.","marks":"3","difficulty":"2"},{"id":"theory>Physics>2001>PART II>13>b>i","subject":"Physics","year":"2001","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"SOUND WAVES : HARMONIES AND OVERTONES","question":"Explain timbre and overtones","images":[],"marking_scheme":"Timbre of a note is one of the characteristic of a note, it distinguishes it from another note which has the same speed and intensity.    Overtones are more quiet than the main note and they provide background which enables us to distinguish the same note played on a different musical instrument. This is also used to differentiate quality musical instruments from poorly made instruments.","marks":"3","difficulty":"2"},{"id":"theory>Physics>2001>PART II>13>b>ii","subject":"Physics","year":"2001","type":"Theory","sub_label":"ii","group":"","topic":"SOUND WAVES : RESONANCE","question":"What is resonance?","images":["data:image/png;base64,"],"marking_scheme":"Resonance occurs when two vibrating bodies caused by a vibrating body setting another body vibrating, having the same natural frequency.","marks":"5","difficulty":"1"},{"id":"theory>Physics>2001>PART II>13>c","subject":"Physics","year":"2001","type":"Theory","sub_label":"c","group":"FINAL","topic":"SOUND WAVES : ECHOES AND REVERBERATION","question":"As a ship approaches a cliff, it siren is sounded and the echo is heard in the ship after 12 seconds.2.1 minutes later the siren was sounded again and the echo was heard 8 seconds later , if the speed of sound in air is 340ms-1. calculate the velocity at which the sip was approaching the cliff.","images":[],"marking_scheme":"V=2xt  where, V = speed of sound  x = distance  t =  time  making x the subject formular   x=Vt2  at first,  X1=340 x 122=2040m  second time,  X2=340 x 82=1360m  distance = 2040 - 1360 = 680m  time = 2.1 minutes = 2.1 x 60 seconds = 126  V=distancetime=680126=5.4ms-1","marks":"5","difficulty":"3"},{"id":"theory>Physics>2001>PART II>14>a","subject":"Physics","year":"2001","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION","question":"Explain the statement 'the capacitance of a capacitor is 5\u00b5F","images":[],"marking_scheme":"The statement the capacitance of a capacitor is 5\u00b5F means that the ratio of the magnitude of the charge q, on any of the plates to the potential difference V, across the capacitor is 5\u00b5F.","marks":"3","difficulty":"2"},{"id":"theory>Physics>2001>PART II>14>b>i","subject":"Physics","year":"2001","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION","question":"State the factors upon which the capacitance of a parallel plate capacitor  depend","images":[],"marking_scheme":"The factors include  - Emissivity of the material  - Area of the plate  - Distance between the plates","marks":"2","difficulty":"2"},{"id":"theory>Physics>2001>PART II>14>b>ii","subject":"Physics","year":"2001","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION","question":"State how the capacitance depends on each of these factors stated in (b)(i)","images":[],"marking_scheme":"- The capacitance depends directly on the emmisivity of the material.  - The capacitance varies directly with the area of the plate.  - The capacitance varies indirectly with the distance between the plates.","marks":"2","difficulty":"1"},{"id":"theory>Physics>2001>PART II>14>c>i","subject":"Physics","year":"2001","type":"Theory","sub_label":"i","group":"","topic":"ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION","question":"A series arrangement of three capacitor of values 8\u00b5F, 12\u00b5F and 24\u00b5F is connected in series with a 90-V battery    Draw an open circuit diagram for this arrangement","images":["data:image/png;base64,"],"marking_scheme":"Open Circuit Diagram","marks":"4","difficulty":"2"},{"id":"theory>Physics>2001>PART II>14>c>ii","subject":"Physics","year":"2001","type":"Theory","sub_label":"ii","group":"FINAL","topic":"ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION","question":"A series arrangement of three capacitor of values 8\u00b5F, 12\u00b5F and 24\u00b5F is connected in series with a 90-V battery  calculate the effective capacitance in the circuit","images":[],"marking_scheme":"Arranged in series,  1C1+1C2+1C3=1C  =18+112+124=624=14  Therefore, C = 4\u00b5F","marks":"3","difficulty":"3"},{"id":"theory>Physics>2001>PART II>14>c>iii","subject":"Physics","year":"2001","type":"Theory","sub_label":"iii","group":"","topic":"ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION","question":"A series arrangement of three capacitor of values 8\u00b5F, 12\u00b5F and 24\u00b5F is connected in series with a 90-V battery  On closed circuit , calculate the charge on each capacitor when full charged","images":[],"marking_scheme":"C=qV  making q the subject of formular  q = CV  therefore,  q = 4 x 10-6 x 90  \u21d2 360 x 10-6A = 3.6 x 10-4A","marks":"3","difficulty":"3"},{"id":"theory>Physics>2001>PART II>14>c>iv","subject":"Physics","year":"2001","type":"Theory","sub_label":"iv","group":"FINAL","topic":"ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION","question":"A series arrangement of three capacitor of values 8\u00b5F, 12\u00b5F and 24\u00b5F is connected in series with a 90-V battery  Determine the p.d across the 8\u00b5F capacitor.","images":[],"marking_scheme":"C=qV  making V the subject formular,  V=qC  V=0.000368 x 10-6=0.000360.000008=45V","marks":"3","difficulty":"3"},{"id":"theory>Physics>2001>PART II>15>a","subject":"Physics","year":"2001","type":"Theory","sub_label":"a","group":"","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"When nitrogen (atomic mass = 14, atomic number = 7) is bombarded with neutons, the collision result indisintegration in which alpha particls are prodduced .Represent this transmutation in a symbolic equation.","images":[],"marking_scheme":"Mass of neutron + Nitrogen nucleus = 1 + 14 = 15  Mass of alpha (\u03b1) particles = 4  Mass of X atom produced = 15 - 4 = 11  This is boron  Therefore, the nuclear reaction is   147N + 10n \u2192 42He + 115B","marks":"4","difficulty":"3"},{"id":"theory>Physics>2001>PART II>15>b>i","subject":"Physics","year":"2001","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"How does a radioactive atom differ from a stable one ?","images":[],"marking_scheme":"The difference between a radioactive atom and a stable atom is the nucleus, the nucleus of a stable atom has a force which keeps all the protons and neutrons in the atom together (at the nucleus) while the radioactive atom has an unstable nucleus.","marks":"3","difficulty":"2"},{"id":"theory>Physics>2001>PART II>15>b>ii","subject":"Physics","year":"2001","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"Explain 'half life'","images":[],"marking_scheme":"The half life of a substance is defined as the time taken for half of the atoms in any given substance to decay  T=0.692\u22cb  T = half life   \u22cb = decay constant","marks":"2","difficulty":"1"},{"id":"theory>Physics>2001>PART II>15>b>iii","subject":"Physics","year":"2001","type":"Theory","sub_label":"iii","group":"FINAL","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"A sample of radioactive material has a half life 35 days. calculate the fraction of the original quantity that will remain after 105 days.","images":[],"marking_scheme":"Let X be the original number of quantity  After 33days, x/2 have disintegrated  x/2 remains   After another 35days, 1/2 of x/2 have disintegrated   Therefore,x4remains  After another 35 days, 1/2 of x/4 have disintegrated   Therefore, 1/8 of x remains   Therefore after 35 + 35 + 35 = 105days   18remains","marks":"3","difficulty":"2"},{"id":"theory>Physics>2001>PART II>15>c>i","subject":"Physics","year":"2001","type":"Theory","sub_label":"i","group":"FINAL","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"Light of wavelenght 5.00\u00d710-7m is incident on a material of work function 1.90 ev. calculate    Photon energy","images":[],"marking_scheme":"Photonenergy(E)=hc\u22cb=(6.6 x 10-34)(3 x 108)5 x 10-7  Therefore, E = 3.96 x 10-19","marks":"3","difficulty":"3"},{"id":"theory>Physics>2001>PART II>15>c>ii","subject":"Physics","year":"2001","type":"Theory","sub_label":"ii","group":"FINAL","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"Light of wavelenght 5.00\u00d710-7m is incident on a material of work function 1.90 ev. calculate  kinetic energy of the most energetic photo electron","images":[],"marking_scheme":"Kinetic energy = E - W  K.E = (2.475 - 1.9)  W = 1.9eV = 1.6 x 10-19   = 3.044 x 1019  K.E = 3.96 x 10-19 = 3.0441019   = 9.2 x 10-20J","marks":"3","difficulty":"3"},{"id":"theory>Physics>2001>PART II>15>c>iii","subject":"Physics","year":"2001","type":"Theory","sub_label":"iii","group":"FINAL","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"Light of wavelenght 5.00\u00d710-7m is incident on a material of work function 1.90 ev. calculate  stopping potential.[plancks constant h = 6.6 \u00d710-34Js][C = 3.0 \u00d7 108ms-2,][leV = 1.6 *times1019J]","images":[],"marking_scheme":"eVs = Emax  V=(9.2 x 10-20)1.6 x 10-19J = 0.575V","marks":"2","difficulty":"3"}];